export const getGetRecordingGemsUrl = (id: number,
    params?: GetRecordingGemsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/recordings/${id}/gems?${stringifiedParams}` : `/api/recordings/${id}/gems`
}

